export function buildOpenClawExport({ manifest, artifacts, claims, rawClaims }) {
  const displayName = manifest.subject?.display_name ?? manifest.id;

  return {
    "AGENTS.md": buildAgents(displayName, manifest),
    "SOUL.md": buildSoul(artifacts.SOUL),
    "USER.md": buildUser(artifacts.USER),
    "MEMORY.md": buildMemory(claims),
    "memory/README.md": buildMemoryReadme(displayName),
    "memory/claims.jsonl": rawClaims
  };
}

function buildAgents(displayName, manifest) {
  return [
    `# OpenClaw Workspace: ${displayName}`,
    "",
    "This workspace was generated by Persona Capsule for OpenClaw-style chat and memory runtimes.",
    "",
    "## Operating Rules",
    "",
    "- Treat `SOUL.md`, `USER.md`, `MEMORY.md`, and `memory/claims.jsonl` as runtime guidance.",
    "- Do not silently merge runtime memories into the canonical capsule.",
    "- Write proposed memory deltas under `memory/` for human review.",
    "- Preserve uncertainty labels from claims when answering.",
    "- Never claim biological or conscious continuity unless the capsule explicitly supports it.",
    "",
    "## Capsule Metadata",
    "",
    `- Capsule: ${manifest.id}`,
    `- Version: ${manifest.version}`,
    `- Mode: ${manifest.mode}`,
    ""
  ].join("\n");
}

function buildSoul(soul) {
  return [
    soul.trim(),
    "",
    "## OpenClaw Runtime Guidance",
    "",
    "- Use this as conversational posture and persona guidance.",
    "- Prefer evidence-backed continuity over theatrical imitation.",
    ""
  ].join("\n");
}

function buildUser(user) {
  return [
    user.trim(),
    "",
    "## OpenClaw Runtime Guidance",
    "",
    "- Use this file to preserve relationship context for the current workspace.",
    "- Do not expand relationship claims beyond supporting evidence.",
    ""
  ].join("\n");
}

function buildMemory(claims) {
  const rememberClaims = claims.filter((claim) => claim.type !== "boundary");
  const boundaryClaims = claims.filter((claim) => claim.type === "boundary");

  return [
    "# MEMORY",
    "",
    "Generated from evidence-backed Persona Capsule claims for OpenClaw runtime use.",
    "",
    "## Remember",
    "",
    ...formatClaimList(rememberClaims),
    "",
    "## Boundaries",
    "",
    ...formatClaimList(boundaryClaims),
    "",
    "## Review Workflow",
    "",
    "- Runtime observations should become proposed deltas, not silent canonical memory edits.",
    "- Re-run Persona Capsule exports after accepted memory changes are reviewed upstream.",
    ""
  ].join("\n");
}

function buildMemoryReadme(displayName) {
  return [
    `# Runtime Memory Deltas: ${displayName}`,
    "",
    "Runtime memory deltas belong here.",
    "",
    "Use this directory for OpenClaw session notes, proposed memory changes, rejected memory records, and review artifacts. Do not overwrite `claims.jsonl`; it is generated from the canonical capsule.",
    ""
  ].join("\n");
}

function formatClaimList(claims) {
  if (claims.length === 0) {
    return ["- No claims available."];
  }

  return claims.map((claim) => `- **${claim.id}** (${claim.type}, ${claim.confidence}): ${claim.text}`);
}
